"use client";

/* ════════════════════════════════════════════════════════════════════════
   BridgeAddSupplier — write surface for registering a new supplier.
   Ported from /Users/mac/Downloads/MAGELLAN UX/Bridge/Opertation/
   magellan-bridge-add-supplier.html

   Pattern (per Bridge style guide §3-5):
   - Drop-to-fill zone at the top
   - Form card with grouped fields
   - Live "What this creates" consequence read with two tiers
   - Commit bar with Cancel + Create supplier → action
   ════════════════════════════════════════════════════════════════════════ */

import { useState } from "react";
import { useBridge } from "@/features/bridge/hooks/use-bridge";

type Role = "Primary" | "Backup" | "One-off";

const COUNTRIES = [
  { name: "Thailand", cur: "THB", domestic: true },
  { name: "China", cur: "CNY" },
  { name: "Netherlands", cur: "EUR" },
  { name: "Belgium", cur: "EUR" },
  { name: "Japan", cur: "JPY" },
  { name: "United States", cur: "USD" },
];

const SUPPLIES = [
  "Bouquets", "Arrangements", "Plants", "Cakes", "Chocolates", "Packaging", "Components",
];

const TERMS = [
  "Prepaid",
  "On delivery (COD)",
  "Net 7",
  "Net 15",
  "Net 30",
  "Net 60",
  "50% deposit + balance",
  "Deposit required",
];

export function BridgeAddSupplier() {
  const { setPage } = useBridge();

  const [name, setName] = useState("");
  const [supplies, setSupplies] = useState<string | null>(null);
  const [role, setRole] = useState<Role>("Primary");
  const [country, setCountry] = useState<string | null>(null);
  const [currency, setCurrency] = useState("");
  const [lead, setLead] = useState("");
  const [moq, setMoq] = useState("");
  const [terms, setTerms] = useState<string | null>(null);
  const [contact, setContact] = useState("");
  const [notes, setNotes] = useState("");
  const [openMenu, setOpenMenu] = useState<"supplies" | "country" | "terms" | null>(null);
  const [created, setCreated] = useState(false);

  const countryObj = country ? COUNTRIES.find((c) => c.name === country) : null;
  const inferredCurrency = countryObj?.cur ?? "";
  const effectiveCurrency = currency || inferredCurrency;
  const origin = countryObj ? (countryObj.domestic ? "domestic" : "import") : null;

  const filled = [name, supplies, country, lead, terms].filter(Boolean).length;
  const enoughToCommit = filled >= 4;

  // Derived consequence reads (mostly inferred placeholders)
  const isPrimaryNoBackup = role === "Primary";
  const leadNum = parseInt(lead) || 0;
  const buffer = leadNum > 0 ? Math.max(2, Math.round(leadNum * 0.3)) : null;
  const termsFloat = terms?.startsWith("Net") ? terms.replace("Net ", "+") + " days" : terms === "Prepaid" ? "−0 days (prepaid)" : "—";

  const create = () => {
    setCreated(true);
    setTimeout(() => {
      setCreated(false);
      setPage("home");
    }, 1500);
  };

  return (
    <div className="bridge-content">
      <div className="bridge-page-head">
        <div className="bridge-page-head-icon">
          <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.8" strokeLinecap="round" strokeLinejoin="round">
            <path d="M3 21 L3 8 L12 3 L21 8 L21 21" />
            <path d="M3 21 L21 21" />
            <rect x="9" y="13" width="6" height="8" />
          </svg>
        </div>
        <div>
          <div className="bridge-page-head-title">Add Supplier</div>
          <div className="bridge-page-head-sub">
            Register a vendor — Magellan tracks lead time and on-time reliability, and shows the dependency it creates.
          </div>
        </div>
      </div>

      {/* Drop to fill */}
      <div className="bridge-ni-drop">
        <div className="bridge-ni-drop-icon">
          <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.7" strokeLinecap="round" strokeLinejoin="round">
            <path d="M12 16 L12 4 M12 4 L8 8 M12 4 L16 8" />
            <path d="M4 14 L4 19 A1 1 0 0 0 5 20 L19 20 A1 1 0 0 0 20 19 L20 14" />
          </svg>
        </div>
        <div className="bridge-ni-drop-text">
          <div className="bridge-ni-drop-title">
            Drop a supplier&rsquo;s line sheet, invoice, or business card — or fill it in below
          </div>
          <div className="bridge-ni-drop-sub">
            Magellan reads it and fills the contact, terms, and lead time. Everything stays editable.
          </div>
        </div>
        <button className="bridge-ni-drop-browse" type="button">Choose file</button>
      </div>

      {/* The supplier card */}
      <div className="bridge-ni-card">
        <div className="bridge-ni-card-head">
          <span className="bridge-ni-section">The supplier</span>
          <span className="bridge-ni-source manual">✏ Entering manually</span>
        </div>
        <div className="bridge-ni-grid">
          <div className="bridge-ni-field bridge-ni-span">
            <span className="bridge-ni-label">Supplier name</span>
            <input
              className="bridge-ni-input"
              type="text"
              placeholder="e.g. Nordic Floral Wholesale"
              value={name}
              onChange={(e) => setName(e.target.value)}
            />
          </div>

          <div className="bridge-ni-field">
            <span className="bridge-ni-label">Supplies</span>
            <div
              className={`bridge-ni-select${openMenu === "supplies" ? " open" : ""}`}
              onClick={() => setOpenMenu((m) => (m === "supplies" ? null : "supplies"))}
            >
              <span className={supplies ? "" : "ph"}>{supplies ?? "Choose categories"}</span>
              <span className="chev">▾</span>
              {openMenu === "supplies" && (
                <div className="bridge-ni-menu open">
                  {SUPPLIES.map((s) => (
                    <div
                      key={s}
                      className="bridge-ni-menu-item"
                      onClick={(e) => {
                        e.stopPropagation();
                        setSupplies(s);
                        setOpenMenu(null);
                      }}
                    >
                      {s}
                    </div>
                  ))}
                </div>
              )}
            </div>
          </div>

          <div className="bridge-ni-field">
            <span className="bridge-ni-label">Role</span>
            <div className="bridge-ni-seg">
              {(["Primary", "Backup", "One-off"] as Role[]).map((r) => (
                <button
                  key={r}
                  className={role === r ? "on" : ""}
                  onClick={() => setRole(r)}
                  type="button"
                >
                  {r}
                </button>
              ))}
            </div>
          </div>

          <div className="bridge-ni-field">
            <span className="bridge-ni-label">Country</span>
            <div
              className={`bridge-ni-select${openMenu === "country" ? " open" : ""}`}
              onClick={() => setOpenMenu((m) => (m === "country" ? null : "country"))}
            >
              <span className={country ? "" : "ph"}>{country ?? "Choose country"}</span>
              {origin && <span className="meta">{origin}</span>}
              <span className="chev">▾</span>
              {openMenu === "country" && (
                <div className="bridge-ni-menu open">
                  {COUNTRIES.map((c) => (
                    <div
                      key={c.name}
                      className="bridge-ni-menu-item"
                      onClick={(e) => {
                        e.stopPropagation();
                        setCountry(c.name);
                        setOpenMenu(null);
                      }}
                    >
                      {c.name}
                      <span className="sub">{c.domestic ? "domestic" : "import"}</span>
                    </div>
                  ))}
                </div>
              )}
            </div>
          </div>
          <div className="bridge-ni-field">
            <span className="bridge-ni-label">Currency</span>
            <input
              className="bridge-ni-input"
              type="text"
              placeholder="auto from country"
              value={effectiveCurrency}
              onChange={(e) => setCurrency(e.target.value)}
            />
          </div>

          <div className="bridge-ni-field">
            <span className="bridge-ni-label">Lead time</span>
            <input
              className="bridge-ni-input"
              type="text"
              placeholder="0 days"
              value={lead}
              onChange={(e) => setLead(e.target.value)}
            />
          </div>
          <div className="bridge-ni-field">
            <span className="bridge-ni-label">Min order (MOQ)</span>
            <input
              className="bridge-ni-input"
              type="text"
              placeholder="$0"
              value={moq}
              onChange={(e) => setMoq(e.target.value)}
            />
          </div>

          <div className="bridge-ni-field">
            <span className="bridge-ni-label">Payment terms</span>
            <div
              className={`bridge-ni-select${openMenu === "terms" ? " open" : ""}`}
              onClick={() => setOpenMenu((m) => (m === "terms" ? null : "terms"))}
            >
              <span className={terms ? "" : "ph"}>{terms ?? "Choose terms"}</span>
              <span className="chev">▾</span>
              {openMenu === "terms" && (
                <div className="bridge-ni-menu open">
                  {TERMS.map((t) => (
                    <div
                      key={t}
                      className="bridge-ni-menu-item"
                      onClick={(e) => {
                        e.stopPropagation();
                        setTerms(t);
                        setOpenMenu(null);
                      }}
                    >
                      {t}
                    </div>
                  ))}
                </div>
              )}
            </div>
          </div>
          <div className="bridge-ni-field">
            <span className="bridge-ni-label">Contact</span>
            <input
              className="bridge-ni-input"
              type="text"
              placeholder="Name, phone, or email"
              value={contact}
              onChange={(e) => setContact(e.target.value)}
            />
          </div>

          <div className="bridge-ni-field bridge-ni-span">
            <span className="bridge-ni-label">
              Notes
              <span className="bridge-ni-hint">
                the messy real-world stuff — ships Tue/Fri, MOQ waived over $5K, ask for Lek
              </span>
            </span>
            <input
              className="bridge-ni-input"
              type="text"
              placeholder="Anything that doesn't fit a field above"
              value={notes}
              onChange={(e) => setNotes(e.target.value)}
            />
          </div>
        </div>
      </div>

      {/* What this creates */}
      <div className="bridge-ni-outcome">
        <div className="bridge-ni-outcome-head">
          <span className="m-mark">M</span> What this creates
          <span className="bridge-ni-outcome-prov">Inferred — reliability builds as POs land</span>
        </div>

        <div className="bridge-ni-outcome-tier">
          <div className="bridge-ni-tier-label">Dependency</div>
          <div className="bridge-ni-outcome-grid">
            <div className="bridge-ni-out">
              <span className="k">SKUs relying on this</span>
              <span className="v">—</span>
              <span className="kk">set once linked</span>
            </div>
            <div className="bridge-ni-out">
              <span className="k">Category exposure</span>
              <span className="v">{supplies ? `${supplies}` : "—"}</span>
              <span className="kk">capital sourced here</span>
            </div>
            <div className="bridge-ni-out">
              <span className="k">Concentration</span>
              <span className="v">—</span>
              <span className="kk">share of category supply</span>
            </div>
            <div className="bridge-ni-out">
              <span className="k">Single point of failure</span>
              <span className={`v${isPrimaryNoBackup && role === "Primary" ? " alert" : ""}`}>
                {isPrimaryNoBackup ? "Yes" : "—"}
              </span>
              <span className="kk">no backup if primary</span>
            </div>
          </div>
        </div>

        <div className="bridge-ni-outcome-tier">
          <div className="bridge-ni-tier-label">Reliability &amp; timing</div>
          <div className="bridge-ni-outcome-grid">
            <div className="bridge-ni-out">
              <span className="k">Lead time</span>
              <span className="v">{lead ? `${leadNum}d` : "—"}</span>
              <span className="kk">order to arrival</span>
            </div>
            <div className="bridge-ni-out">
              <span className="k">On-time rate</span>
              <span className="v">—</span>
              <span className="kk">tracked from POs</span>
            </div>
            <div className="bridge-ni-out">
              <span className="k">Reorder buffer</span>
              <span className="v">{buffer ? `${buffer}d` : "—"}</span>
              <span className="kk">safety days from lead</span>
            </div>
            <div className="bridge-ni-out">
              <span className="k">Terms float</span>
              <span className="v">{terms ? termsFloat : "—"}</span>
              <span className="kk">cash timing benefit</span>
            </div>
          </div>
        </div>

        <div className="bridge-ni-outcome-note">
          Dependency figures fill in as you link SKUs to this supplier; <b>on-time reliability</b> is measured from real POs over time, not assumed. A <b>primary</b> supplier with no backup is flagged as a single point of failure. Once created, it appears in <b>Suppliers</b> and feeds the reorder verdict on every SKU it supplies.
        </div>
      </div>

      {/* Commit bar */}
      <div className="bridge-ni-commit">
        <div className="bridge-ni-commit-note">
          This drafts the supplier record — <b>nothing is linked</b> to SKUs until you confirm. Reversible.
        </div>
        <div className="bridge-ni-commit-btns">
          <button className="bridge-ni-cancel" type="button" onClick={() => setPage("home")}>
            Cancel
          </button>
          <button
            className={`bridge-ni-create${created ? " done" : ""}`}
            type="button"
            onClick={create}
            disabled={!enoughToCommit || created}
          >
            {created ? "Supplier drafted ✓" : "Create supplier →"}
          </button>
        </div>
      </div>
    </div>
  );
}
